Here's a complete example. I'll create the three key files for a REST API wrapper MCP server.

**1. Program.cs — stdio transport with DI**

```csharp
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

var builder = Host.CreateApplicationBuilder(args);

// CRITICAL: route all logging to stderr so stdout stays clean for JSON-RPC
builder.Logging.AddConsole(options =>
    options.LogToStandardErrorThreshold = LogLevel.Trace);

// Register HttpClient for DI — tools receive it via constructor injection
builder.Services.AddHttpClient("WeatherApi", client =>
{
    client.BaseAddress = new Uri("https://api.weather.gov");
    client.DefaultRequestHeaders.Add("User-Agent", "WeatherMcpServer/1.0");
});

builder.Services.AddMcpServer()
    .WithStdioServerTransport()
    .WithToolsFromAssembly();   // discovers all [McpServerToolType] classes

await builder.Build().RunAsync();
```

**2. WeatherTools.cs — tool class wrapping a REST API**

```csharp
using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerToolType]
public class WeatherTools(IHttpClientFactory httpClientFactory, ILogger<WeatherTools> logger)
{
    [McpServerTool, Description("Get the current weather forecast for a US location by latitude and longitude.")]
    public async Task<string> GetForecast(
        [Description("Latitude of the location (e.g. 39.7456)")] double latitude,
        [Description("Longitude of the location (e.g. -97.0892)")] double longitude,
        CancellationToken cancellationToken = default)
    {
        var client = httpClientFactory.CreateClient("WeatherApi");

        logger.LogInformation("Fetching forecast for ({Lat}, {Lon})", latitude, longitude);

        // Step 1: get the grid point
        var pointJson = await client.GetStringAsync(
            $"/points/{latitude},{longitude}", cancellationToken);

        using var pointDoc = JsonDocument.Parse(pointJson);
        var forecastUrl = pointDoc.RootElement
            .GetProperty("properties")
            .GetProperty("forecast")
            .GetString()
            ?? throw new InvalidOperationException("No forecast URL returned");

        // Step 2: fetch the actual forecast
        var forecast = await client.GetStringAsync(forecastUrl, cancellationToken);

        using var forecastDoc = JsonDocument.Parse(forecast);
        var periods = forecastDoc.RootElement
            .GetProperty("properties")
            .GetProperty("periods");

        // Return a concise summary of the first few periods
        var results = new List<string>();
        foreach (var period in periods.EnumerateArray().Take(3))
        {
            var name = period.GetProperty("name").GetString();
            var detail = period.GetProperty("detailedForecast").GetString();
            results.Add($"**{name}**: {detail}");
        }

        return string.Join("\n\n", results);
    }

    [McpServerTool, Description("Get active weather alerts for a US state.")]
    public async Task<string> GetAlerts(
        [Description("Two-letter US state code (e.g. CA, NY, TX)")] string stateCode,
        CancellationToken cancellationToken = default)
    {
        var client = httpClientFactory.CreateClient("WeatherApi");

        logger.LogInformation("Fetching alerts for state {State}", stateCode);

        var json = await client.GetStringAsync(
            $"/alerts/active?area={stateCode}", cancellationToken);

        using var doc = JsonDocument.Parse(json);
        var features = doc.RootElement.GetProperty("features");

        if (features.GetArrayLength() == 0)
            return $"No active alerts for {stateCode}.";

        var alerts = new List<string>();
        foreach (var feature in features.EnumerateArray().Take(5))
        {
            var props = feature.GetProperty("properties");
            var headline = props.GetProperty("headline").GetString();
            var severity = props.GetProperty("severity").GetString();
            alerts.Add($"[{severity}] {headline}");
        }

        return string.Join("\n", alerts);
    }
}
```

**3. How DI works for MCP tools**

The SDK has two injection styles:

| Style | Class type | How services arrive |
|---|---|---|
| **Constructor injection** | Non-static class | Services in the constructor, tool params in each method |
| **Method injection** | Static class | Both services and tool params as method parameters |

**Key rule:** The SDK automatically distinguishes tool parameters from injected services. Types registered in DI (`HttpClient`, `ILogger<T>`, `IHttpClientFactory`, etc.) and framework types (`CancellationToken`, `IMcpServer`, `IProgress<>`) are **injected silently** — they never appear in the tool's JSON schema shown to the LLM. Only parameters with `[Description]` are exposed as tool inputs.

For non-static classes (like `WeatherTools` above), the SDK creates a new instance per tool call, resolving constructor dependencies from the DI container each time. This means the class is effectively **transient** scoped.

**To scaffold this project yourself:**

```bash
dotnet new mcpserver -n WeatherMcpServer
cd WeatherMcpServer
# Replace the generated files with the code above
dotnet build && dotnet run
```
